// ===================================================
// WF-10 Step 1: POST 본문 파싱 + 입력값 검증
// 필수 필드: member_id, score, total
// 보안: PASS_THRESHOLD(11)와 TOTAL_QUESTIONS(15)는 서버 고정 상수
// 클라이언트에서 pass_threshold를 보내도 무시
// ===================================================

const input = $input.first().json;
const body = input.body || input;

// === 서버 고정 상수 (클라이언트 조작 방지) ===
const PASS_THRESHOLD = 11;   // 15문항 중 11문항 이상 정답 (73%)
const TOTAL_QUESTIONS = 15;

// === 텍스트 정제 ===
function sanitizeText(str, maxLen) {
  if (!str) return '';
  maxLen = maxLen || 500;
  return String(str)
    .replace(/[\x00-\x08\x0B\x0C\x0E-\x1F]/g, '')
    .trim()
    .substring(0, maxLen);
}

// === 필수 필드 추출 ===
const memberId = sanitizeText(body.member_id, 100);
const scoreRaw = body.score;
const totalRaw = body.total;

// === 필수 필드 검증 ===
if (!memberId) {
  return [{
    json: {
      _valid: false,
      _errorResponse: {
        success: false,
        error: {
          code: 'NOT_LOGGED_IN',
          message: '로그인이 필요합니다.'
        },
        timestamp: new Date().toISOString()
      }
    }
  }];
}

// === 점수 파라미터 숫자 변환 + 유효성 검증 ===
const score = Number(scoreRaw);
const total = Number(totalRaw);

if (isNaN(score) || isNaN(total)) {
  return [{
    json: {
      _valid: false,
      _errorResponse: {
        success: false,
        error: {
          code: 'INVALID_SCORE',
          message: 'score, total은 숫자여야 합니다.'
        },
        timestamp: new Date().toISOString()
      }
    }
  }];
}

if (total !== TOTAL_QUESTIONS) {
  return [{
    json: {
      _valid: false,
      _errorResponse: {
        success: false,
        error: {
          code: 'INVALID_SCORE',
          message: 'total은 ' + TOTAL_QUESTIONS + '이어야 합니다.'
        },
        timestamp: new Date().toISOString()
      }
    }
  }];
}

if (score < 0 || score > TOTAL_QUESTIONS || score !== Math.floor(score)) {
  return [{
    json: {
      _valid: false,
      _errorResponse: {
        success: false,
        error: {
          code: 'INVALID_SCORE',
          message: 'score는 0~' + TOTAL_QUESTIONS + ' 사이의 정수여야 합니다.'
        },
        timestamp: new Date().toISOString()
      }
    }
  }];
}

// === 합격 여부 판정 (서버 고정 기준) ===
const passed = score >= PASS_THRESHOLD;

return [{
  json: {
    _valid: true,
    memberId,
    score,
    total: TOTAL_QUESTIONS,
    passed,
    passThreshold: PASS_THRESHOLD
  }
}];

// ===================================================
// WF-10 Step 2: 파트너 인증 확인
// ===================================================

const response = $input.first().json;
const partnerList = response.list || [];
const validData = $('Validate Input').first().json;

if (partnerList.length === 0) {
  return [{
    json: {
      _partnerFound: false,
      _errorResponse: {
        success: false,
        error: {
          code: 'NOT_PARTNER',
          message: '파트너로 등록되지 않은 회원입니다.'
        },
        timestamp: new Date().toISOString()
      }
    }
  }];
}

const partner = partnerList[0];

if (partner.status !== 'active') {
  return [{
    json: {
      _partnerFound: false,
      _errorResponse: {
        success: false,
        error: {
          code: 'PARTNER_INACTIVE',
          message: '비활성 상태의 파트너 계정입니다.'
        },
        timestamp: new Date().toISOString()
      }
    }
  }];
}

return [{
  json: {
    _partnerFound: true,
    _partner: {
      Id: partner.Id || partner.id,
      partner_code: partner.partner_code || '',
      partner_name: partner.partner_name || '',
      member_id: partner.member_id || '',
      email: partner.email || '',
      grade: partner.grade || 'SILVER'
    },
    _input: validData
  }
}];

